		pow2Zeros := power(2, seg.zeros, MOD)

		// 3. Calculate V_seg = (termOnes * pow2Zeros) % MOD
		vSeg := (termOnes * pow2Zeros) % MOD

		// 4. Calculate the shift factor: 2^(L_prefix) (mod MOD)
		// The length of the prefix processed so far is (Total Length of all previous segments).
		// currentPowerOf2 is $2^{\sum L_{prev}}$.

		// 5. Contribution = (V_seg * currentPowerOf2) % MOD
		contribution := (vSeg * currentPowerOf2) % MOD

		// 6. Update total result
		result = (result + contribution) % MOD

		// 7. Update currentPowerOf2 for the next segment: 2^(L_prefix + L_current) = 2^L_prefix * 2^L_current
		lengthCurrent := totalLength
		pow2LengthCurrent := power(2, lengthCurrent, MOD)
		currentPowerOf2 = (currentPowerOf2 * pow2LengthCurrent) % MOD
	}

	return result
}
