package main

import (
	"sort"
)

// solve calculates the maximum integer value representable by concatenating the given binary fragments, modulo 10^9 + 7.
func solve(nums1 []int64, nums0 []int64) int64 {
	MOD := int64(1e9 + 7)
	n := len(nums1)

	// Represent each fragment by a value that helps in sorting.
	// The goal is to sort the fragments (A and B) such that if A comes before B,
	// the resulting number is maximized. This is equivalent to comparing A+B vs B+A.
	// We need a custom comparator.

	type Fragment struct {
		ones  int64
		zeros int64
	}

	fragments := make([]Fragment, n)
	for i := 0; i < n; i++ {
		fragments[i] = Fragment{ones: nums1[i], zeros: nums0[i]}
	}

	// Custom sort logic: Fragment A comes before Fragment B if (A + B) >= (B + A) lexicographically.
	// A = 1...1 0...0 (ones_A ones)
	// B = 1...1 0...0 (ones_B ones)
	// A+B vs B+A comparison is equivalent to comparing the strings formed by concatenating the blocks.

	// We define a comparison function based on the lexicographical comparison of the resulting concatenated strings.
	// A fragment is defined by (ones, zeros).
	// String representation of A: "1"*ones_A + "0"*zeros_A
	// String representation of B: "1"*ones_B + "0"*zeros_B

	// Comparing A+B vs B+A is complex for direct numerical comparison due to variable lengths.
	// Since we are aiming for the lexicographically largest string (which corresponds to the largest integer value),
	// we use string comparison logic based on the concatenation.

	sort.Slice(fragments, func(i, j int) bool {
		A := fragments[i]
		B := fragments[j]

		// Compare A followed by B (A+B) vs B followed by A (B+A) lexicographically.
		// A+B: (1^A)(0^A) + (1^B)(0^B)
		// B+A: (1^B)(0^B) + (1^A)(0^A)

		// This comparison is tricky to implement purely with ints/longs without generating strings,
		// but since the total length is bounded (<= 2*10^5), generating strings is feasible.
		// However, let's stick to the standard greedy approach for this type of problem:
		// Sort based on which one contributes more to the higher order bits.

		// The sorting key for maximum number is based on comparing S1+S2 vs S2+S1.
		// If S1+S2 > S2+S1, S1 should come before S2.

		// We construct the two potential concatenations as strings for comparison.
		sA := make([]byte, A.ones+A.zeros)
		for k := int64(0); k < A.ones; k++ {
			sA[k] = '1'
		}
		for k := A.ones; k < A.ones+A.zeros; k++ {
			sA[k] = '0'
		}

		sB := make([]byte, B.ones+B.zeros)
		for k := int64(0); k < B.ones; k++ {
			sB[k] = '1'
		}
		for k := B.ones; k < B.ones+B.zeros; k++ {
			sB[k] = '0'
		}

		// A+B
		sAB := append([]byte(nil), sA...)
		sAB = append(sAB, sB...)

		// B+A
		sBA := append([]byte(nil), sB...)
		sBA = append(sBA, sA...)

		// Lexicographical comparison: return true if sAB > sBA
		return string(sAB) > string(sBA)
	})

	// Now, concatenate the sorted fragments and calculate the resulting modulo value.
	// Result = Sum [ value(Fragment_i) * 2^(Total length after i) ] mod MOD

	currentPowerOf2 := int64(1) // Represents 2^0 initially
	totalLength := int64(0)
	result := int64(0)

	// Iterate backwards through the sorted fragments to calculate the total value efficiently.
	// The last fragment contributes the smallest power of 2.
	for i := n - 1; i >= 0; i-- {
		f := fragments[i]

		// The current fragment has length L = f.ones + f.zeros.
		L := f.ones + f.zeros

		// Value of the current fragment: (2^f.ones - 1) * 2^f.zeros
		// 1^ones 0^zeros = (2^ones - 1) * 2^zeros

		// Calculate 2^f.zeros mod MOD. This is the weight of the leading '1' of the fragment.
		// We need power(2, f.zeros) mod MOD.

		pow2Zeros := power(2, f.zeros, MOD)

		// Value contribution from the '1's part: (2^f.ones - 1)
		// We need 2^f.ones - 1 mod MOD.
		pow2Ones := power(2, f.ones, MOD)
		onesValue := (pow2Ones - 1 + MOD) % MOD

		// Value of the fragment = onesValue * pow2Zeros mod MOD
		fragmentValue := (onesValue * pow2Zeros) % MOD

		// This fragment starts at position `totalLength` from the right end.
		// The contribution of this fragment to the total sum is fragmentValue * 2^totalLength (where totalLength is the length of all subsequent fragments).

		// Since we are iterating backwards, totalLength is the length of the suffix already processed.
		// The current fragment's value needs to be shifted left by `totalLength` bits.

		contribution := (fragmentValue * power(2, totalLength, MOD)) % MOD

		result = (result + contribution) % MOD

		// Update total length and power for the next (previous) fragment
		totalLength += L
	}

	return result
}

// Helper function for modular exponentiation: (base^exp) % mod
func power(base, exp, mod int64) int64 {
	res := int64(1)
	base %= mod
	for exp > 0 {
		if exp%2 == 1 {
			res = (res * base) % mod
		}
		base = (base * base) % mod
		exp /= 2
	}
	return res
}
